{"orgId":"00000000-0000-0000-0000-000000000000","tenantId":"00000000-0000-0000-0000-000000000000","ruleId":"d8dfa5f68b9947ab94e3ee6baa57a783","ruleName":"Security Operations Admin User","ruleDescription":"This rule applies to security operations admin users that configure, manage, monitor, and respond to threats within the organization.","createdBy":"","createdByName":null,"lastUpdatedBy":"","lastUpdatedByName":null,"lastUpdateTime":null,"ruleDefinition":null,"kqlQuery":"
        let filteredDevices = 
            Nodes
            | where Label == 'device'
            | where Properties has_cs 'criticalityLevel'
            | where Properties has_cs 'Security Operations Admin Device' or Properties has_cs 'SecurityOperations Admin Device'
            | distinct SourceNodeId = Id;
        let filteredEdges = Edges | where Label == 'frequently logged in by';
        let singleLoginDevices = 
            filteredDevices
            | join kind=inner hint.shufflekey=SourceNodeId filteredEdges on SourceNodeId
            | summarize loginCount = dcount(TargetNodeId) by SourceNodeId
            | where loginCount == 1;
        let usersLoggedIntoSingleLoginDevices = 
            singleLoginDevices
            | join kind=inner hint.shufflekey=SourceNodeId filteredEdges on SourceNodeId
            | distinct Id = TargetNodeId;
        let userDetails = 
            usersLoggedIntoSingleLoginDevices
            | join kind=inner hint.shufflekey=Id (
                Nodes
                | where Label == 'user'
            ) on Id
            | extend RuleId = 'd8dfa5f68b9947ab94e3ee6baa57a783';
        userDetails","isDisabled":false,"actions":[{"actionType":"CriticalityLevel","value":2,"creationTime":"0001-01-01T00:00:00"}],"affectedAssetsCount":0,"creationTime":null,"ruleType":"Predefined","criticalityLevel":2,"isDeleted":false,"lastExecutionTime":"2026-05-03T09:56:00.3583485Z","timestamp":"2026-05-03T10:03:38.8062623Z","assetType":"Identities","classificationValue":"SecurityOperationsAdminUser"}

